export default function NovaCampanha() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const [currentStep, setCurrentStep] = useState(0);
    const [formData, setFormData] = useState({
        name: '',
        objective: '',
        special_ad_categories: [],
        buying_type: 'AUCTION',
        daily_budget: '',
        start_time: '',
        platforms: ['facebook', 'instagram'],
    });

    const createCampaign = useMutation({
        mutationFn: async (data: any) => {
            // Check for company_id first
            if (!user?.company_id) {
                throw new Error('User does not belong to a company');
            }

            const { data: campaign, error } = await supabase
                .from('campaigns')
                .insert([
                    {
                        ...data,
                        company_id: user.company_id,
                        status: 'PAUSED', // Default status
                        account_id: 'act_123456789', // Placeholder account ID, should come from context/selection
                        daily_budget: parseFloat(data.daily_budget),
                        lifetime_budget: 0, // Default
                    },
                ])
                .select()
                .single();

            if (error) throw error;
            return campaign;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['campaigns'] });
            toast.success('Campanha criada com sucesso!');
            toast('Funcionalidade em desenvolvimento', {
                description: 'A criação real na Meta API será implementada em breve.',
                duration: 5000,
            });
            navigate('/campanhas');
        },
        onError: (error) => {
            toast.error(`Erro ao criar campanha: ${error.message}`);
        },
    });

    const handleNext = () => {
        if (currentStep < steps.length - 1) {
            setCurrentStep((prev) => prev + 1);
        } else {
            createCampaign.mutate(formData);
        }
    };

    const handleBack = () => {
        if (currentStep > 0) {
            setCurrentStep((prev) => prev - 1);
        }
    };

    const updateFormData = (field: string, value: any) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
    };

    const renderStepContent = () => {
        switch (currentStep) {
            case 0:
                return (
                    <div className="space-y-6 animate-in fade-in slide-in-from-right-8 duration-500">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {objectives.map((obj) => (
                                <div
                                    key={obj.id}
                                    onClick={() => updateFormData('objective', obj.id)}
                                    className={`relative p-6 rounded-3xl border-2 cursor-pointer transition-all hover:scale-105 group overflow-hidden ${formData.objective === obj.id
                                            ? `border-${obj.color} bg-${obj.color}/10 shadow-[0_0_30px_-10px_var(--tw-shadow-color)] shadow-${obj.color}/30`
                                            : 'border-white/5 bg-white/[0.02] hover:border-white/20 hover:bg-white/5'
                                        }`}
                                >
                                    <div className="flex flex-col h-full relative z-10">
                                        <div className={`p-4 rounded-2xl w-fit mb-4 ${formData.objective === obj.id
                                                ? `bg-${obj.color} text-ch-black`
                                                : `bg-white/5 text-${obj.color}`
                                            }`}>
                                            <obj.icon className="w-6 h-6" />
                                        </div>
                                        <h3 className="text-lg font-bold text-ch-white mb-2 uppercase tracking-tight">{obj.label}</h3>
                                        <p className="text-xs font-medium text-ch-text-dimmed leading-relaxed">{obj.description}</p>
                                    </div>
                                    {/* Selection Indicator */}
                                    {formData.objective === obj.id && (
                                        <div className={`absolute top-4 right-4 text-${obj.color}`}>
                                            <CheckCircle2 className="w-6 h-6 fill-current" />
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                );

            case 1:
                return (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-8 duration-500 max-w-2xl mx-auto">
                        <div className="space-y-4">
                            <Label className="text-xs font-bold text-ch-text-dimmed uppercase tracking-wider">Nome da Campanha</Label>
                            <Input
                                value={formData.name}
                                onChange={(e) => updateFormData('name', e.target.value)}
                                placeholder="Ex: Campanha de Vendas - Verão 2024"
                                className="h-14 bg-white/5 border-white/10 text-ch-white placeholder:text-ch-text-dimmed/30 rounded-xl focus:border-ch-orange/50 transition-colors text-lg font-medium"
                            />
                        </div>

                        <div className="space-y-4">
                            <Label className="text-xs font-bold text-ch-text-dimmed uppercase tracking-wider">Categorias de Anúncio Especial</Label>
                            <div className="p-6 rounded-2xl border border-white/5 bg-white/[0.02] space-y-4">
                                <div className="flex items-center space-x-3">
                                    <Checkbox id="credit" className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:text-ch-black" />
                                    <label htmlFor="credit" className="text-sm font-medium text-ch-white cursor-pointer">Crédito</label>
                                </div>
                                <div className="flex items-center space-x-3">
                                    <Checkbox id="employment" className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:text-ch-black" />
                                    <label htmlFor="employment" className="text-sm font-medium text-ch-white cursor-pointer">Emprego</label>
                                </div>
                                <div className="flex items-center space-x-3">
                                    <Checkbox id="housing" className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:text-ch-black" />
                                    <label htmlFor="housing" className="text-sm font-medium text-ch-white cursor-pointer">Moradia</label>
                                </div>
                                <div className="flex items-center space-x-3">
                                    <Checkbox id="social" className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:text-ch-black" />
                                    <label htmlFor="social" className="text-sm font-medium text-ch-white cursor-pointer">Temas Sociais, Eleições ou Política</label>
                                </div>
                            </div>
                        </div>
                    </div>
                );

            case 2:
                 return (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-8 duration-500 flex flex-col items-center justify-center py-12 text-center">
                        <div className="w-24 h-24 bg-ch-orange/10 rounded-full flex items-center justify-center mb-6">
                            <Users className="w-10 h-10 text-ch-orange" />
                        </div>
                        <h3 className="text-2xl font-bold text-ch-white uppercase tracking-tight">Definição de Público</h3>
                        <p className="text-ch-text-dimmed max-w-md mx-auto">
                            A configuração detalhada de público será feita no nível do Conjunto de Anúncios após a criação da campanha.
                        </p>
                        <Button variant="outline" className="mt-4 border-ch-orange/20 text-ch-orange hover:bg-ch-orange/10 pointer-events-none">
                            Configuração Automática Habilitada
                        </Button>
                    </div>
                 );

            case 3:
                return (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-8 duration-500 max-w-xl mx-auto">
                         <div className="space-y-6">
                            <Label className="text-xs font-bold text-ch-text-dimmed uppercase tracking-wider block text-center">Orçamento Diário da Campanha</Label>
                            <div className="relative">
                                <span className="absolute left-6 top-1/2 -translate-y-1/2 text-2xl font-bold text-ch-text-dimmed">R$</span>
                                <Input
                                    type="number"
                                    value={formData.daily_budget}
                                    onChange={(e) => updateFormData('daily_budget', e.target.value)}
                                    placeholder="0,00"
                                    className="pl-16 h-24 text-4xl font-black text-center bg-transparent border-b-2 border-white/10 rounded-none focus:border-ch-orange focus:ring-0 transition-all placeholder:text-white/5"
                                />
                            </div>
                            <p className="text-center text-xs text-ch-text-dimmed">
                                Valor estimado de alcance: <strong className="text-emerald-400">1.2k - 3.5k pessoas/dia</strong>
                            </p>
                         </div>
                    </div>
                );

            case 4:
                return (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-8 duration-500 max-w-2xl mx-auto">
                        <div className="glass p-8 rounded-[2rem] border-white/5 bg-white/[0.02] space-y-6 text-center">
                            <div className="w-16 h-16 bg-emerald-500/10 rounded-2xl flex items-center justify-center mx-auto mb-4">
                                <Rocket className="w-8 h-8 text-emerald-400" />
                            </div>
                            <h3 className="text-2xl font-bold text-ch-white uppercase tracking-tight">Pronto para Lançar?</h3>
                            <p className="text-ch-text-dimmed">Revise os detalhes da sua campanha antes de publicar.</p>

                            <div className="grid grid-cols-2 gap-4 text-left bg-white/5 p-6 rounded-2xl">
                                <div>
                                    <span className="text-[10px] font-bold text-ch-text-dimmed uppercase tracking-wider">Nome</span>
                                    <p className="text-ch-white font-medium">{formData.name}</p>
                                </div>
                                <div>
                                    <span className="text-[10px] font-bold text-ch-text-dimmed uppercase tracking-wider">Objetivo</span>
                                    <p className="text-ch-white font-medium">{formData.objective}</p>
                                </div>
                                <div>
                                    <span className="text-[10px] font-bold text-ch-text-dimmed uppercase tracking-wider">Orçamento</span>
                                    <p className="text-emerald-400 font-bold">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(formData.daily_budget))}/dia</p>
                                </div>
                            </div>
                        </div>
                    </div>
                );
            default:
                return null;
        }
    };

    return (
        <div className="min-h-screen p-6 pb-20 flex flex-col max-w-6xl mx-auto">
            {/* Header */}
            <div className="flex items-center gap-4 mb-12">
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => navigate('/campanhas')}
                    className="hover:bg-white/5 rounded-xl"
                >
                    <ArrowLeft className="w-5 h-5 text-ch-text-dimmed" />
                </Button>
                <div>
                    <h1 className="text-2xl font-bold text-ch-white uppercase tracking-tight">Nova Campanha Neural</h1>
                    <p className="text-xs text-ch-text-dimmed font-medium mt-1">Configure sua estratégia de aquisição</p>
                </div>
            </div>

            {/* Stepper */}
            <div className="flex justify-between items-center mb-16 relative px-10">
                {/* Progress Bar Background */}
                <div className="absolute left-0 top-1/2 -translate-y-1/2 w-full h-1 bg-white/5 -z-10" />

                {/* Active Progress Bar */}
                <motion.div 
                    className="absolute left-0 top-1/2 -translate-y-1/2 h-1 bg-ch-orange -z-10 transition-all duration-500"
                    initial={{ width: '0%' }}
                    animate={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}
                />

                {steps.map((step, index) => {
                    const isActive = index === currentStep;
                    const isCompleted = index < currentStep;

                    return (
                        <div key={step.id} className="flex flex-col items-center gap-3 bg-ch-black px-4 relative z-10">
                            <motion.div
                                initial={false}
                                animate={{
                                    scale: isActive ? 1.1 : 1,
                                    borderColor: isActive || isCompleted ? 'var(--ch-orange)' : 'rgba(255,255,255,0.1)',
                                    backgroundColor: isActive ? 'var(--ch-orange)' : isCompleted ? 'var(--ch-black)' : 'var(--ch-black)'
                                }}
                                className={`w-12 h-12 rounded-2xl border-2 flex items-center justify-center transition-all duration-300 ${
                                    isCompleted ? 'text-ch-orange' : isActive ? 'text-ch-black shadow-[0_0_20px_-5px_var(--ch-orange)]' : 'text-ch-text-dimmed'
                                }`}
                            >
                                <step.icon className="w-5 h-5" />
                            </motion.div>
                            <span className={`text-[10px] font-black uppercase tracking-widest transition-colors ${
                                isActive ? 'text-ch-white' : 'text-ch-text-dimmed'
                            }`}>
                                {step.label}
                            </span>
                        </div>
                    );
                })}
            </div>

            {/* Main Content Area */}
            <div className="flex-1">
                {renderStepContent()}
            </div>

            {/* Footer Navigation */}
            <div className="flex justify-between items-center mt-12 pt-8 border-t border-white/5">
                <Button
                    variant="ghost"
                    onClick={handleBack}
                    disabled={currentStep === 0}
                    className="h-12 px-8 rounded-xl font-bold uppercase text-[10px] tracking-widest text-ch-text-dimmed hover:text-ch-white hover:bg-white/5 disabled:opacity-30"
                >
                    Voltar
                </Button>

                <Button
                    onClick={handleNext}
                    disabled={
                        (currentStep === 0 && !formData.objective) ||
                        (currentStep === 1 && !formData.name) ||
                        (currentStep === 3 && !formData.daily_budget) ||
                        createCampaign.isPending
                    }
                    className="h-12 px-10 bg-ch-orange text-ch-black hover:bg-ch-orange/90 rounded-xl font-black uppercase text-[10px] tracking-widest shadow-lg shadow-ch-orange/20 transition-all hover:scale-105 active:scale-95 disabled:opacity-50 disabled:scale-100"
                >
                    {createCampaign.isPending ? (
                        <span className="flex items-center gap-2">
                            <Zap className="w-4 h-4 animate-spin" /> Processando
                        </span>
                    ) : currentStep === steps.length - 1 ? (
                        <span className="flex items-center gap-2">
                             Lançar Campanha <Rocket className="w-4 h-4" />
                        </span>
                    ) : (
                        <span className="flex items-center gap-2">
                            Continuar <ChevronRight className="w-4 h-4" />
                        </span>
                    )}
                </Button>
            </div>
        </div>
    );
}

